DO $$
DECLARE
  d   jsonb := $jdata$[{"slug":"skydio-x10","name":"Skydio X10","manufacturer":"Skydio","type":"drone","introduced_year":2023,"specs_json":{"weight_kg":1.36,"max_speed_ms":20,"endurance_min":42,"ip_rating":"IP55","battery_wh":106,"comms":"Skydio Secure Link","obstacle_avoidance":"360 degree AI","camera":"50MP EO + thermal IR","compute":"Qualcomm Snapdragon SoC","storage_gb":64},"failure_modes":[{"component":"obstacle avoidance cameras \u2014 contamination and calibration drift","symptom":"obstacle avoidance system switches to degraded mode; drone slows and widens clearance margins; false collision warnings in open airspace","root_cause":"Skydio X10 uses 6 fisheye cameras for 360-degree obstacle avoidance; dust, pollen, or water droplets on camera windows degrade AI confidence scores; thermal shock from indoor-to-outdoor transitions causes lens focus drift","severity":"high","mtbf_hours":100,"source_urls":["unverified-training-data"],"confidence":"low","tags":["camera","obstacle-avoidance","contamination","calibration","AI"],"repair_protocol":{"title":"Obstacle Avoidance Camera Cleaning and Recalibration","steps":[{"step":1,"action":"Power off; inspect all 6 camera windows under oblique light for dust, smudges, or water spots","tool":"bright flashlight"},{"step":2,"action":"Blow loose dust with sensor-safe air blower; never use compressed air cans (propellant can freeze lens coating)","tool":"sensor-safe rocket blower"},{"step":3,"action":"Wipe each camera window with dry optical microfiber cloth in straight strokes; use fresh section for each window","tool":"optical microfiber cloth"},{"step":4,"action":"If smudge persists: one drop lens cleaning solution on cloth only (never on lens); wipe; dry with fresh cloth section","tool":"lens cleaning solution (Pancro or equivalent)"},{"step":5,"action":"Power on; allow 10 minutes temperature equilibration; run Skydio obstacle avoidance calibration via Skydio app","tool":"Skydio app, open area with known objects at 5m"},{"step":6,"action":"Verify obstacle detection range > 10m in all quadrants with 1x1m test panel","tool":"1x1m flat test panel, measuring tape"}],"tools_required":["sensor-safe rocket blower","optical microfiber cloth","lens cleaning solution","Skydio app","1x1m test panel","measuring tape"],"parts":[],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"obstacle_avoidance_confidence_score","signal_source":"Skydio autonomy telemetry","threshold_value":0.7,"threshold_operator":"<","threshold_unit":"confidence 0-1","lead_time_hours":2,"confidence":0.8}]},{"component":"Qualcomm SoC \u2014 thermal throttling from blocked vent","symptom":"AI inference latency increases; obstacle detection response time > 200ms; drone reduces maximum speed autonomously; SoC temperature alarm","root_cause":"X10 relies on passive convection through body vents for SoC thermal management; fine dust accumulates in vent mesh reducing airflow; SoC thermal throttles at 85C junction temperature","severity":"medium","mtbf_hours":500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["compute","thermal","Qualcomm","SoC","vent"],"repair_protocol":{"title":"Body Vent Cleaning for SoC Thermal Management","steps":[{"step":1,"action":"Power off; identify vent mesh locations on drone body (typically 4 vent slots on lower body)","tool":"flashlight"},{"step":2,"action":"Use sensor-safe blower to blow dust out from inside outward via battery bay access (blow into body, out through vents)","tool":"sensor-safe rocket blower"},{"step":3,"action":"Use soft horsehair brush to remove any remaining debris from vent mesh","tool":"soft horsehair brush"},{"step":4,"action":"Power on; perform 10-minute flight; verify SoC temperature stays < 78C via Skydio flight data export","tool":"Skydio app flight data export"}],"tools_required":["sensor-safe rocket blower","soft horsehair brush","Skydio app"],"parts":[],"labor_minutes":10,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"soc_temperature_c","signal_source":"Skydio telemetry","threshold_value":80,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":2,"confidence":0.8},{"signal_name":"obstacle_response_latency_ms","signal_source":"autonomy system metrics","threshold_value":180,"threshold_operator":">","threshold_unit":"milliseconds","lead_time_hours":1,"confidence":0.72}]},{"component":"motor bearing \u2014 pitting from grit contamination","symptom":"motor vibration signature changes; one motor RPM differs from commanded by > 5%; audible grinding under load; motor current 15%+ above peers","root_cause":"X10 IP55 motor shaft seals degrade at 18-24 months; fine silica dust from construction inspection or agricultural environments enters motor and causes bearing race pitting; bearing noise often only detectable at high RPM","severity":"high","mtbf_hours":800,"source_urls":["unverified-training-data"],"confidence":"low","tags":["motor","bearing","dust","wear","IP55"],"repair_protocol":{"title":"Motor Bearing Inspection and Motor Replacement","steps":[{"step":1,"action":"Power off; remove propeller (3x M2 screws)","tool":"JIS #000 screwdriver"},{"step":2,"action":"Spin motor shaft by hand at 1 revolution per second; feel for roughness or grinding; even slight roughness = replace motor","tool":null},{"step":3,"action":"Remove motor from arm (3x M2 mounting screws from inside arm tube); disconnect 3-phase wire connector","tool":"JIS #000 screwdriver, tweezers"},{"step":4,"action":"Install new motor; reconnect 3-phase wire connector (orientation must match \u2014 verify in Skydio service manual)","tool":"JIS #000 screwdriver, tweezers","warning":"Phase wire reversal will cause motor to spin wrong direction \u2014 verify connector orientation before powering on"},{"step":5,"action":"Reinstall propeller; power on; run motor self-test via Skydio Enterprise Dashboard; verify vibration < 0.8g RMS","tool":"Skydio Enterprise Dashboard"}],"tools_required":["JIS #000 screwdriver","tweezers","Skydio Enterprise Dashboard"],"parts":[{"part_name":"Skydio X10 Motor Assembly","part_number":"SKD-X10-MOTOR-01","supplier":"Skydio Enterprise Support","unit_cost_usd":145,"qty":1}],"labor_minutes":25,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_vibration_rms_g","signal_source":"IMU motor health monitor","threshold_value":1.0,"threshold_operator":">","threshold_unit":"g RMS per motor","lead_time_hours":4,"confidence":0.82}]},{"component":"thermal IR payload microbolometer \u2014 pixel dropout","symptom":"thermal image shows fixed dark or bright pixels in same location frame-to-frame; cold spots pattern in uniform-temperature target; thermal measurement accuracy degrades","root_cause":"uncooled microbolometer detector has pixel non-uniformity that increases with thermal cycling; hot-pixel count increases after 5000+ flight hours; periodic flat field correction (FFC) can compensate but cannot recover pixels with > 50% response loss","severity":"medium","mtbf_hours":5000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sensor","thermal","IR","microbolometer","payload"],"repair_protocol":{"title":"Thermal Payload FFC Calibration and Sensor Assessment","steps":[{"step":1,"action":"Run flat field correction: in Skydio app, navigate to Thermal Settings > Calibration > Run FFC; allow 30 seconds","tool":"Skydio app"},{"step":2,"action":"Capture thermal image of uniformly-heated blackbody or flat wall > 2m from drone; count hot/cold pixel clusters","tool":"uniform wall, measuring tape"},{"step":3,"action":"If < 10 fixed pixels: continue service after FFC recalibration","tool":null},{"step":4,"action":"If > 50 fixed pixels or > 1% of frame: escalate to Skydio Enterprise Support for sensor replacement \u2014 not field-serviceable","tool":"Skydio Enterprise Support"}],"tools_required":["Skydio app","uniform flat surface for thermal reference"],"parts":[],"labor_minutes":15,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"fixed_pixel_count","signal_source":"thermal camera diagnostics","threshold_value":25,"threshold_operator":">","threshold_unit":"fixed pixels","lead_time_hours":48,"confidence":0.75}]},{"component":"LiHV battery \u2014 cold weather sudden voltage collapse","symptom":"battery voltage drops sharply during high-throttle manoeuvre in ambient < 5C; drone enters forced landing; post-flight battery shows < 20% SOC despite pre-flight indication of 60%+","root_cause":"LiHV chemistry used in X10 battery has higher nominal voltage (4.35V/cell) but poor low-temperature performance; internal resistance rises 3-4x below 5C; rapid throttle demand causes voltage sag below cutoff threshold triggering emergency land","severity":"critical","mtbf_hours":400,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","LiHV","cold-weather","safety","critical"],"repair_protocol":{"title":"Cold Weather Battery Pre-Warming Protocol","steps":[{"step":1,"action":"In ambient < 10C, warm battery to minimum 15C before flight: insert battery in drone and idle aircraft (motors off) for 5 minutes with aircraft powered on; battery self-heating from electronics sufficient","tool":null},{"step":2,"action":"Verify battery temperature via Skydio app Battery Health screen shows > 15C before takeoff","tool":"Skydio app"},{"step":3,"action":"Reduce maximum speed setting to 80% in cold conditions; reduce mission duration to 70% of nominal endurance","tool":"Skydio app flight settings"},{"step":4,"action":"Store batteries at room temperature between flights \u2014 never store cold batteries charged","tool":null}],"tools_required":["Skydio app"],"parts":[],"labor_minutes":10,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"battery_temp_c","signal_source":"Skydio battery telemetry","threshold_value":12,"threshold_operator":"<","threshold_unit":"celsius at takeoff","lead_time_hours":1,"confidence":0.88}]},{"component":"IP55 port covers \u2014 loss from repeated access","symptom":"USB-C and microSD port covers missing; water ingress risk through open ports during IP55-rated operations; moisture detected in storage port area","root_cause":"Skydio X10 port covers use thin silicone rubber attached to body; repeated port access for data download detaches cover hinge; covers frequently lost in field; once lost, IP55 rating at those ports is void","severity":"medium","mtbf_hours":200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sealing","IP55","port-cover","water-ingress","prevention"],"repair_protocol":{"title":"Port Cover Replacement and Water Ingress Prevention","steps":[{"step":1,"action":"Inspect all port covers (USB-C, microSD, battery contact) before each mission for presence and seating","tool":null},{"step":2,"action":"Replace missing port covers from spares kit; press firmly until click","tool":null},{"step":3,"action":"If hinge attachment point is damaged, apply thin bead of Loctite 401 to hinge attachment point; allow 5 minutes cure","tool":"Loctite 401 cyanoacrylate"},{"step":4,"action":"Never fly in rain without all port covers installed and confirmed seated","tool":null}],"tools_required":["Skydio X10 port cover spares kit","Loctite 401"],"parts":[{"part_name":"Skydio X10 Port Cover Set","part_number":"SKD-X10-PORTCOVERS","supplier":"Skydio Enterprise Support","unit_cost_usd":18,"qty":2}],"labor_minutes":5,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"port_cover_present","signal_source":"pre-flight visual checklist","threshold_value":1,"threshold_operator":"<","threshold_unit":"boolean (0=missing)","lead_time_hours":0,"confidence":0.95}]}],"suppliers":[{"name":"Skydio Enterprise Support","website":"https://www.skydio.com/enterprise","region":"NA","component_types":["motor","port covers","battery","thermal payload"],"lead_time_days":5,"risk_level":"medium","notes":"Skydio hardware is US-controlled and has export restrictions"}],"research_sources":["unverified-training-data"]},{"slug":"zipline-p2","name":"Zipline P2 Zip","manufacturer":"Zipline","type":"delivery_air","introduced_year":2023,"specs_json":{"weight_kg":8.5,"payload_kg":2.5,"max_speed_ms":34,"range_km":32,"battery":"LiPo custom 6-cell","wingspan_m":2.0,"drive":"pusher propeller fixed-wing","launch":"pneumatic catapult","recovery":"arrestor wire","descent":"parachute delivery pod"},"failure_modes":[{"component":"servo actuator \u2014 elevator/aileron gear train wear","symptom":"control surface has play > 2 degrees; autopilot reports control surface limit reached during routine manoeuvre; aircraft oscillates in pitch or roll","root_cause":"servo output gear train uses plastic final stage gears (weight optimisation); repeated high-speed flight with gusty conditions causes gear tooth wear; aileron servos see highest duty cycle in turbulence","severity":"critical","mtbf_hours":400,"source_urls":["unverified-training-data"],"confidence":"low","tags":["servo","gear","wear","flight-critical","control-surface"],"repair_protocol":{"title":"Control Surface Servo Gear Inspection and Replacement","steps":[{"step":1,"action":"With aircraft powered off, manually deflect each control surface; any perceptible freeplay = servo requires replacement","tool":null},{"step":2,"action":"Measure freeplay with protractor at control surface \u2014 > 1.5 degrees requires immediate servo replacement","tool":"digital protractor"},{"step":3,"action":"Remove wing panel per Zipline service procedure; expose servo bay","tool":"Torx T8, T10 drivers"},{"step":4,"action":"Disconnect servo connector; remove servo from bay (3x M2.5 screws); disconnect control horn","tool":"JIS #0 screwdriver"},{"step":5,"action":"Install new servo; reconnect control horn at same hole position; connect servo connector","tool":"JIS #0 screwdriver"},{"step":6,"action":"Run Zipline GCS control surface calibration; verify deflection vs command within 0.5 degrees across full travel","tool":"Zipline GCS software, laptop"}],"tools_required":["T8 Torx","T10 Torx","JIS #0 screwdriver","digital protractor","Zipline GCS software","laptop"],"parts":[{"part_name":"Zipline P2 Control Servo (field replacement unit)","part_number":"ZL-P2-SERVO-FRU","supplier":"Zipline Field Service","unit_cost_usd":85,"qty":1}],"labor_minutes":45,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"control_surface_freeplay_deg","signal_source":"pre-flight manual check log","threshold_value":1.0,"threshold_operator":">","threshold_unit":"degrees","lead_time_hours":8,"confidence":0.88},{"signal_name":"autopilot_control_limit_event_count","signal_source":"flight controller fault log","threshold_value":2,"threshold_operator":">","threshold_unit":"events per flight","lead_time_hours":4,"confidence":0.8}]},{"component":"pusher propeller \u2014 delamination from UV and fatigue","symptom":"vibration increase > 50% on IMU at cruise speed; aircraft speed reduced by autopilot; visible surface delamination on prop blade","root_cause":"P2 pusher prop is CFRP/fiberglass composite; UV exposure from equatorial deployment sites (Ghana, Rwanda, Nigeria) accelerates matrix resin degradation; high-cycle fatigue from 34m/s cruise and repeated catapult launches","severity":"critical","mtbf_hours":200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["propeller","delamination","UV","composite","safety"],"repair_protocol":{"title":"Pusher Propeller Inspection and Replacement","steps":[{"step":1,"action":"Pre-flight mandatory: inspect propeller under bright light for delamination blistering or any visible damage; feel for surface roughness","tool":"flashlight, clean hands"},{"step":2,"action":"Tap prop blade with fingernail along span \u2014 hollow sound indicates subsurface delamination; reject any blade with hollow tap response","tool":null},{"step":3,"action":"Remove propeller spinner (3x M3 screws); remove propeller nut (CCW thread \u2014 turn clockwise to loosen)","tool":"JIS #1 screwdriver, 13mm socket, thread direction warning"},{"step":4,"action":"Install new prop; tighten nut to 12 Nm; reinstall spinner","tool":"torque wrench 0-20 Nm, 13mm socket"},{"step":5,"action":"Perform ground run-up at 75% power for 30 seconds; verify IMU vibration < baseline +20%","tool":"Zipline GCS"}],"tools_required":["flashlight","JIS #1 screwdriver","13mm socket","torque wrench 0-20 Nm","Zipline GCS"],"parts":[{"part_name":"Zipline P2 Pusher Propeller","part_number":"ZL-P2-PROP-FRU","supplier":"Zipline Field Service","unit_cost_usd":55,"qty":1}],"labor_minutes":15,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"cruise_vibration_rms_g","signal_source":"autopilot IMU","threshold_value":1.5,"threshold_operator":">","threshold_unit":"g RMS at cruise","lead_time_hours":2,"confidence":0.88},{"signal_name":"propeller_flight_count","signal_source":"Zipline GCS operations log","threshold_value":150,"threshold_operator":">","threshold_unit":"flights","lead_time_hours":24,"confidence":0.8}]},{"component":"pitot tube \u2014 blockage from insects or moisture","symptom":"airspeed indication erratic; autopilot enters degraded mode; airspeed reads 0 or > 60m/s at known cruise speed","root_cause":"pitot tube open to airstream for airspeed measurement; small insects (wasps, spiders) create nests inside pitot tube during overnight storage; equatorial humidity causes moisture condensation blockage","severity":"critical","mtbf_hours":200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sensor","pitot","blockage","insect","airspeed","critical"],"repair_protocol":{"title":"Pitot Tube Inspection and Clearing","steps":[{"step":1,"action":"Pre-flight mandatory: visually inspect pitot tube opening; use flashlight to verify clear opening; no nest material visible","tool":"flashlight"},{"step":2,"action":"Blow through pitot tube gently with mouth from aircraft end to clear; air must flow freely through both static and total pressure ports","tool":null,"warning":"Never use compressed air or sharp objects to clear pitot \u2014 can damage pressure sensor diaphragm"},{"step":3,"action":"If blockage persists, use pipe cleaner of appropriate diameter to gently clear tube","tool":"pipe cleaner 3mm diameter"},{"step":4,"action":"After clearing, blow through again to confirm clear passage; perform airspeed calibration ground test","tool":"Zipline GCS airspeed test routine"},{"step":5,"action":"Preventive: install pitot cover during all ground operations and overnight storage; remove cover as part of pre-flight checklist","tool":"pitot tube cover (custom fabric cap)"}],"tools_required":["flashlight","3mm pipe cleaner","Zipline GCS","pitot cover"],"parts":[{"part_name":"Pitot Tube Fabric Cover (pack of 10)","part_number":"ZL-PITOT-COVER-10PK","supplier":"Zipline Field Service","unit_cost_usd":12,"qty":1}],"labor_minutes":10,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"airspeed_reading_at_launch_ms","signal_source":"autopilot airspeed sensor","threshold_value":2,"threshold_operator":"<","threshold_unit":"m/s on ground (should be 0)","lead_time_hours":0,"confidence":0.95}]},{"component":"catapult/arrestor system \u2014 fatigue at launch bracket","symptom":"launch velocity varies > 10% between launches; aircraft enters runway faster than expected; launch abort triggered by autopilot velocity check","root_cause":"pneumatic catapult launch system imparts 15G+ to aircraft at launch; catapult attachment bracket on aircraft fuselage experiences repeated high impulse loads; bracket-to-fuselage bond fatigues at composite interface","severity":"critical","mtbf_hours":600,"source_urls":["unverified-training-data"],"confidence":"low","tags":["launch-system","catapult","structural","fatigue","composite"],"repair_protocol":{"title":"Catapult Bracket Bond Inspection and Recertification","steps":[{"step":1,"action":"After every 500 launches: inspect catapult attachment bracket for visible cracks in surrounding composite or bracket edge separation","tool":"magnifying glass, flashlight, coin tap test"},{"step":2,"action":"Tap coin around bracket perimeter \u2014 hollow sound indicates delamination; any delamination = aircraft grounded","tool":"coin"},{"step":3,"action":"If delamination detected: escalate to Zipline aircraft depot for structural recertification \u2014 not field repairable","tool":null,"warning":"Field repair of load-bearing composite structures requires vacuum bagging and controlled cure \u2014 do not attempt field repair"},{"step":4,"action":"Inspect catapult pneumatic line fitting for cracks or O-ring compression set; replace O-ring if needed","tool":"O-ring removal pick, Molykote 55 lubricant"},{"step":5,"action":"Log launch velocities from last 10 launches; if standard deviation > 1m/s, inspect pneumatic system for leaks","tool":"Zipline GCS launch velocity log"}],"tools_required":["magnifying glass","flashlight","coin","O-ring pick","Molykote 55","Zipline GCS"],"parts":[{"part_name":"Catapult Pneumatic Line O-Ring Kit","part_number":"ZL-CAT-ORING-KIT","supplier":"Zipline Field Service","unit_cost_usd":8,"qty":1}],"labor_minutes":30,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"launch_velocity_stddev_ms","signal_source":"Zipline GCS launch velocity log","threshold_value":0.8,"threshold_operator":">","threshold_unit":"m/s standard deviation","lead_time_hours":4,"confidence":0.8}]},{"component":"LiPo flight battery \u2014 capacity fade from high-rate cycling","symptom":"flight range drops below 25km; emergency reserve lands at 0% vs 10% expected; battery discharge curve shows flat section indicating dead cell group","root_cause":"P2 catapult launch requires 10C+ discharge rate instantaneously; repeated high-C discharge cycles accelerate LiPo capacity fade; equatorial high-temperature storage between flights further degrades cell chemistry","severity":"high","mtbf_hours":300,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","LiPo","high-rate","capacity-fade","range"],"repair_protocol":{"title":"Flight Battery Capacity Assessment and Replacement","steps":[{"step":1,"action":"Log flight range from last 5 missions; if average < 28km, perform battery capacity test","tool":"Zipline GCS mission records"},{"step":2,"action":"Perform battery capacity discharge test via Zipline battery tester: full charge to 4.20V/cell; discharge at 2C to 3.50V/cell; record Ah","tool":"Zipline battery tester station"},{"step":3,"action":"If measured capacity < 85% of rated: retire battery; log serial number and cycle count","tool":"Zipline battery tester"},{"step":4,"action":"Install new battery; perform 3 break-in charge-discharge cycles at 1C before high-rate service","tool":"Zipline battery tester station"}],"tools_required":["Zipline GCS","Zipline battery tester station"],"parts":[{"part_name":"Zipline P2 Flight LiPo Battery Pack","part_number":"ZL-P2-BATT-FRU","supplier":"Zipline Field Service","unit_cost_usd":380,"qty":1}],"labor_minutes":15,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"average_mission_range_km","signal_source":"Zipline GCS fleet data","threshold_value":28,"threshold_operator":"<","threshold_unit":"kilometers","lead_time_hours":12,"confidence":0.82}]},{"component":"parachute delivery pod \u2014 deployment failure","symptom":"payload pod does not separate from aircraft at delivery point; delivery audit shows package not dropped; aircraft returns with payload","root_cause":"pod release mechanism uses pyrotechnic squib or servo-actuated release; squib moisture degradation in humid equatorial climates; servo release linkage corrosion from humidity","severity":"critical","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["delivery","pod","release","pyrotechnic","critical"],"repair_protocol":{"title":"Delivery Pod Release Mechanism Inspection and Service","steps":[{"step":1,"action":"Inspect pod release servo linkage monthly for corrosion; lubricate all pivot points with Corrosion-X","tool":"Corrosion-X, cotton swab"},{"step":2,"action":"Test release mechanism with inert training pod: command release from GCS; verify pod separates within 100ms of command","tool":"Zipline GCS, inert training pod, timer"},{"step":3,"action":"If release fails: remove pod bay cover; inspect servo arm and release pin for corrosion or binding","tool":"T8 Torx"},{"step":4,"action":"If servo arm corroded: replace servo module (full FRU swap); if release pin bent: replace pin","tool":"JIS #0 screwdriver"},{"step":5,"action":"If pyrotechnic squib system: check squib date code \u2014 replace annually regardless of use; store squibs in dry sealed container","tool":"squib date code label, sealed dry container","warning":"Pyrotechnic squib handling requires operator certification \u2014 never disassemble or probe live squib"}],"tools_required":["Corrosion-X","T8 Torx","JIS #0 screwdriver","Zipline GCS","inert training pod"],"parts":[{"part_name":"Zipline P2 Release Servo Module","part_number":"ZL-P2-RELEASE-SRV","supplier":"Zipline Field Service","unit_cost_usd":65,"qty":1}],"labor_minutes":30,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"release_mechanism_test_pass","signal_source":"pre-flight release test log","threshold_value":1,"threshold_operator":"<","threshold_unit":"boolean (0=failed test)","lead_time_hours":0,"confidence":0.95},{"signal_name":"days_since_release_mechanism_service","signal_source":"maintenance log","threshold_value":30,"threshold_operator":">","threshold_unit":"days","lead_time_hours":48,"confidence":0.8}]},{"component":"pitot heater \u2014 open circuit failure in cold elevation deployments","symptom":"pitot tube icing in missions above 2500m altitude or ambient < 2C; airspeed reads zero after 5 minutes at altitude; autopilot enters airspeed-unavailable mode","root_cause":"P2 pitot heater is thin-film resistive element; vibration-induced fatigue crack in heater lead wire causes open circuit; heater circuit not monitored in real-time \u2014 failure only apparent when icing occurs","severity":"high","mtbf_hours":1500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["pitot","heater","icing","electrical","altitude"],"repair_protocol":{"title":"Pitot Heater Circuit Continuity Test and Repair","steps":[{"step":1,"action":"Monthly maintenance: with aircraft powered off, measure pitot heater resistance at aircraft connector \u2014 expect 8-12 ohms; open circuit (>1Mohm) = heater failed","tool":"digital multimeter"},{"step":2,"action":"If open circuit: remove nose fairing (6x T8 screws); trace heater wire to fracture point","tool":"T8 Torx, digital multimeter, spudger"},{"step":3,"action":"Repair wire fracture with solder splice; insulate with dual-wall heat shrink; ensure strain relief at pitot mount","tool":"soldering iron, dual-wall heat shrink, heat gun"},{"step":4,"action":"Verify heater resistance restores to 8-12 ohms; reinstall fairing","tool":"digital multimeter, T8 Torx"},{"step":5,"action":"Test heater function: power on aircraft; enable pitot heat from GCS; verify pitot tube surface reaches 40C within 60 seconds via IR thermometer","tool":"Zipline GCS, IR thermometer"}],"tools_required":["digital multimeter","T8 Torx","soldering iron","dual-wall heat shrink","heat gun","IR thermometer","Zipline GCS"],"parts":[{"part_name":"Pitot Heater Wire Repair Kit (22AWG silicone wire + heat shrink)","part_number":"ZL-PITOT-HEAT-REPAIR","supplier":"Zipline Field Service","unit_cost_usd":12,"qty":1}],"labor_minutes":40,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"pitot_heater_resistance_ohm","signal_source":"monthly maintenance DMM check","threshold_value":15,"threshold_operator":">","threshold_unit":"ohms (open circuit if very high)","lead_time_hours":168,"confidence":0.88}]}],"suppliers":[{"name":"Zipline Field Service","website":"https://www.flyzipline.com","region":"NA","component_types":["all P2 FRU parts","battery","propeller","servo","pitot covers"],"lead_time_days":7,"risk_level":"high","notes":"Zipline operates closed service model \u2014 all parts through Zipline directly; no third-party parts supported"}],"research_sources":["unverified-training-data"]}]$jdata$::jsonb;
  p   jsonb;
  fm  jsonb;
  sig jsonb;
  pid  uuid;
  fmid uuid;
BEGIN
  FOR p IN SELECT value FROM jsonb_array_elements(d)
  LOOP
    SELECT id INTO pid FROM platforms WHERE slug = p->>'slug';
    IF pid IS NULL THEN
      INSERT INTO platforms (slug,name,manufacturer,type,introduced_year,specs_json,techmedix_status)
      VALUES (p->>'slug',p->>'name',p->>'manufacturer',p->>'type',
              NULLIF(p->>'introduced_year','null')::integer,
              COALESCE(p->'specs_json','{}'::jsonb),'supported')
      RETURNING id INTO pid;
    END IF;
    FOR fm IN SELECT value FROM jsonb_array_elements(p->'failure_modes')
    LOOP
      INSERT INTO failure_modes (platform_id,component,symptom,root_cause,severity,mtbf_hours,source_urls,confidence,tags)
      VALUES (pid, fm->>'component', fm->>'symptom', fm->>'root_cause',
              COALESCE(fm->>'severity','medium'),
              NULLIF(fm->>'mtbf_hours','null')::integer,
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'source_urls','["unverified-training-data"]'::jsonb))),
              COALESCE(fm->>'confidence','low'),
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'tags','[]'::jsonb))))
      ON CONFLICT (platform_id,component,symptom) DO UPDATE SET severity=EXCLUDED.severity, updated_at=now()
      RETURNING id INTO fmid;
      IF fm ? 'repair_protocol' THEN
        INSERT INTO repair_protocols (failure_mode_id,title,steps_json,tools_required,parts_json,labor_minutes,skill_level,source_url,verified_by,version)
        SELECT fmid,
               fm->'repair_protocol'->>'title',
               COALESCE(fm->'repair_protocol'->'steps','[]'::jsonb),
               ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'repair_protocol'->'tools_required','[]'::jsonb))),
               COALESCE(fm->'repair_protocol'->'parts','[]'::jsonb),
               NULLIF(fm->'repair_protocol'->>'labor_minutes','null')::integer,
               COALESCE(fm->'repair_protocol'->>'skill_level','intermediate'),
               fm->'repair_protocol'->>'source_url',
               'research_agent', 1
        WHERE NOT EXISTS (SELECT 1 FROM repair_protocols WHERE failure_mode_id=fmid);
      END IF;
      FOR sig IN SELECT value FROM jsonb_array_elements(COALESCE(fm->'predictive_signals','[]'::jsonb))
      LOOP
        INSERT INTO predictive_signals (failure_mode_id,signal_name,signal_source,threshold_value,threshold_operator,threshold_unit,lead_time_hours,confidence,notes)
        SELECT fmid, sig->>'signal_name', sig->>'signal_source',
               NULLIF(sig->>'threshold_value','null')::numeric,
               COALESCE(sig->>'threshold_operator','>'),
               sig->>'threshold_unit',
               NULLIF(sig->>'lead_time_hours','null')::integer,
               NULLIF(sig->>'confidence','null')::numeric,
               sig->>'notes'
        WHERE NOT EXISTS (SELECT 1 FROM predictive_signals WHERE failure_mode_id=fmid AND signal_name=sig->>'signal_name');
      END LOOP;
    END LOOP;
  END LOOP;
END $$;